const d = $input.first().json;
const question = $('Chat Trigger').first().json.body && $('Chat Trigger').first().json.body.question
  ? $('Chat Trigger').first().json.body.question
  : ($('Chat Trigger').first().json.query && $('Chat Trigger').first().json.query.question
    ? $('Chat Trigger').first().json.query.question
    : '');
function safeParse(val, fallback) {
  if (!val) return fallback;
  try { return JSON.parse(val); } catch(e) { return fallback; }
}
return [{
  json: {
    dataset_id: d.dataset_id,
    filename: d.filename,
    n_rows: d.n_rows,
    n_cols: d.n_cols,
    duplicate_count: d.duplicate_count,
    numericCols: safeParse(d.numeric_cols, []),
    categoricalCols: safeParse(d.categorical_cols, []),
    datetimeCols: safeParse(d.datetime_cols, []),
    profile: safeParse(d.profile_json, {}),
    outlierReport: safeParse(d.outlier_report_json, {}),
    descriptiveStats: safeParse(d.descriptive_stats_json, {}),
    correlationMatrix: safeParse(d.correlation_matrix_json, {}),
    cleanedRows: safeParse(d.cleaned_rows_json, []),
    question: question
  }
}];

